  // modifiers

  modifier onlyFactory() {
    _requireOnlyFactory();

    _;
  }

  // deployment

  constructor() Clone() {
    //
  }

  // internal getters

  function _requireOnlyFactory() internal view {
    require(msg.sender == _getFactory(), MsgSenderIsNotTheFactory());
  }
}
