pragma solidity 0.8.27;

import {EIP712} from "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import {Guarded} from "../access/Guarded.sol";
import {CloneFactory} from "../proxy/CloneFactory.sol";
import {Initializable} from "../utils/Initializable.sol";

contract TokenFactory is EIP712, Guarded, CloneFactory, Initializable {
  struct TokenData {
    bytes32 salt;
    address impl;
    bytes initData;
  }

  bytes32 private constant TOKEN_TYPEHASH =
    keccak256(
      "Token(bytes32 salt,address impl,bytes initData)" //
    );

  // storage

  mapping(address => bytes32) private _tokenSalts;

  // events

  event Initialized(address forwarder, address[] guardians);

  event TokenCreated(
    address token,
    address impl,
    bytes initData,
    uint256 timestamp
  );

  event TokenNotification(
    address token,
    uint8 kind,
    bytes encodedData,
    uint256 timestamp
  );

  // errors

  error MsgSenderIsNotTheToken();

  // modifiers

  modifier onlyToken() {
    _requireOnlyToken();

    _;
  }

  // deployment

  constructor(
    string memory eip712Name,
    address owner,
    address cloneTarget
  ) EIP712(eip712Name, "1") CloneFactory(cloneTarget) {
    _setInitialOwner(owner);
  }

  function initialize(
    address forwarder,
    address[] calldata guardians
  ) external onlyOwner initializeOnce {
    _setForwarder(forwarder);
    _setInitialGuardians(guardians);

    emit Initialized(forwarder, guardians);
  }

  // external getters

  function computeToken(bytes32 salt) external view returns (address) {
    return _computeClone(salt);
  }

  function isToken(address token) external view returns (bool) {
    return _isToken(token);
  }

  function hashToken(
    TokenData calldata tokenData
  ) external view returns (bytes32) {
    return _hashToken(tokenData.salt, tokenData.impl, tokenData.initData);
  }

  // external setters

  function createToken(
    bytes32 salt,
    address impl,
    bytes calldata initData
  ) external onlyOwner {
    _createToken(salt, impl, initData);
  }

  function createToken(
    bytes32 salt,
    address impl,
    bytes calldata initData,
    bytes calldata signature
  ) external {
    bytes32 hash = _hashToken(salt, impl, initData);

    _verifyGuardianSignature(hash, signature);

    _createToken(salt, impl, initData);
  }

  function emitTokenNotification(
    uint8 kind,
    bytes calldata encodedData
  ) external onlyToken {
    _emitTokenNotification(kind, encodedData);
  }

  // private getters

  function _isToken(address token) private view returns (bool) {
    return _tokenSalts[token] != bytes32(0);
  }

  function _hashToken(
    bytes32 salt,
    address impl,
    bytes calldata initData
  ) private view returns (bytes32) {
    return
      _hashTypedDataV4(
        keccak256(
          abi.encode(
            TOKEN_TYPEHASH, //
            salt,
            impl,
            keccak256(initData)
          )
        )
      );
  }

  function _requireOnlyToken() private view {
    require(_isToken(msg.sender), MsgSenderIsNotTheToken());
  }

  // private setters

  function _createToken(
    bytes32 salt,
    address impl,
    bytes calldata initData
  ) private {
    address token = _createClone(salt, impl, initData);

    _tokenSalts[token] = salt;

    emit TokenCreated(token, impl, initData, block.timestamp);
  }

  function _emitTokenNotification(
    uint8 kind,
    bytes calldata encodedData
  ) private {
    emit TokenNotification(msg.sender, kind, encodedData, block.timestamp);
  }
}
","keccak256":"0x02fcdc1b63e23aba9bc6c0ad775546e6fcfeb60c95f00279c3c0279c8ccab258","license":"None"},"contracts/tokens/TokenImpl.sol":{"content":"// SPDX-License-Identifier: None
pragma solidity 0.8.27;

import {EIP712} from "@openzeppelin/contracts/utils/cryptography/EIP712.sol";
import {Ownable} from "../access/Ownable.sol";
import {CloneImpl} from "../proxy/CloneImpl.sol";
import {TokenFactory} from "./TokenFactory.sol";

abstract contract TokenImpl is EIP712, Ownable, CloneImpl {
  // storage

  address private _controller;

  bool private _ready;

  // events

  error TokenAlreadyReady();

  error TokenNotReady();

  error ControllerAlreadyUpdated();

  error MsgSenderIsNotTheController();

  // modifiers

  modifier onlyCurrentManager() {
    _requireOnlyCurrentManager();

    _;
  }
  // modifiers

  modifier onlyReadyOrAnyManager() {
    _requireOnlyReadyOrAnyManager();

    _;
  }

  // deployment

  constructor(string memory eip712Name) EIP712(eip712Name, "1") CloneImpl() {
    //
  }

  // external getters

  function getController() external view returns (address) {
    return _getController();
  }

  function isReady() external view returns (bool) {
    return _isReady();
  }

  // external setters

  function setController(address controller) external onlyCurrentManager {
    require(_getController() != controller, ControllerAlreadyUpdated());

    _setController(controller);
    _afterControllerUpdated(controller);
  }

  function setReady() external onlyOwner {
    require(!_isReady(), TokenAlreadyReady());

    _setReady(true);
    _afterSetReady();
  }

  // internal getters

  function _getController() internal view returns (address) {
    return _controller;
  }

  function _isReady() internal view returns (bool) {
    return _ready;
  }

  function _hashInitialization(
    bytes memory structData
  ) internal view virtual returns (bytes32 result) {
    if (_getFactory() == address(0)) {
      result = _hashTypedDataV4(keccak256(structData));
    }

    return result;
  }

  function _requireOnlyCurrentManager() internal view {
    address msgSender = _msgSender();

    if (!_isReady()) {
      _requireOnlyOwner(msgSender);
    } else {
      require(msgSender == _getController(), MsgSenderIsNotTheController());
    }
  }

  function _requireOnlyReadyOrAnyManager() internal view {
    if (!_isReady()) {
      address msgSender = _msgSender();

      require(
        msgSender == _getController() || msgSender == _getOwner(),
        TokenNotReady()
      );
    }
  }

  // internal setters
  function _setController(address controller) internal {
    _controller = controller;
  }

  function _afterControllerUpdated(address controller) internal {
    _notifyTokenFactory(0x02, abi.encode(controller));
  }

  function _setReady(bool ready) internal {
    _ready = ready;
  }

  function _afterSetReady() internal {
    _notifyTokenFactory(0x00);
  }

  function _afterOwnerUpdated(address owner) internal override {
    super._afterOwnerUpdated(owner);

    _notifyTokenFactory(0x01, abi.encode(owner));
  }

  function _notifyTokenFactory(uint8 kind) internal {
    _notifyTokenFactory(kind, new bytes(0));
  }

  function _notifyTokenFactory(uint8 kind, bytes memory encodedData) internal {
    TokenFactory(_getFactory()).emitTokenNotification(kind, encodedData);
  }
}
